class Solution:
    def minFlipsMonoIncr(self, s: str) -> int:
        n = len(s)
        # try every cut point 0..n: left part all 0, right part all 1
        ones = [0] * (n + 1)
        zeros = [0] * (n + 1)
        for i in range(n):
            ones[i + 1] = ones[i] + (1 if s[i] == '1' else 0)
        for i in range(n - 1, -1, -1):
            zeros[i] = zeros[i + 1] + (1 if s[i] == '0' else 0)
        return min(ones[k] + zeros[k] for k in range(n + 1))

